using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service = new();

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectProperties()
    {
        var items = CreateItems(("Widget", 9.99m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(items, order.Items);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        var items = CreateItems(("Widget", 12.50m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(37.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalAcrossAllItems()
    {
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 4));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(40m, order.Total); // (10*2) + (5*4)
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(() => _service.CreateOrder("cust-1", []));
    }

    [TestMethod]
    public void GetOrder_WhenOrderExists_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 5m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var retrieved = _service.GetOrder(created.Id);

        Assert.AreEqual(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_WhenOrderDoesNotExist_ReturnsNull()
    {
        var result = _service.GetOrder("nonexistent-id");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WhenCustomerHasOrders_ReturnsAllCustomerOrders()
    {
        var items = CreateItems(("Widget", 5m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WhenCustomerHasNoOrders_ReturnsEmptyList()
